const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const redisClient = redis.createClient({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379
});

redisClient.on('error', (err) => console.error('Redis Client Error', err));
redisClient.connect();

const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;
const CODE_EXPIRATION = 600;
const MAX_ATTEMPTS = 10;
const LOCKOUT_DURATION = 3600;

function generateSecureCode() {
  const randomBytes = crypto.randomBytes(4);
  const code = (randomBytes.readUInt32BE(0) % 1000000).toString().padStart(6, '0');
  return code;
}

function validatePhoneNumber(phone) {
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
}

function sanitizeUserId(userId) {
  if (typeof userId !== 'string' || userId.length === 0 || userId.length > 100) {
    return null;
  }
  const sanitized = userId.replace(/[^a-zA-Z0-9_-]/g, '');
  return sanitized.length > 0 ? sanitized : null;
}

async function isUserLockedOut(userId) {
  const lockoutKey = `lockout:${userId}`;
  const lockout = await redisClient.get(lockoutKey);
  return lockout !== null;
}

async function incrementAttempts(userId) {
  const attemptsKey = `attempts:${userId}`;
  const attempts = await redisClient.incr(attemptsKey);
  await redisClient.expire(attemptsKey, CODE_EXPIRATION);
  
  if (attempts >= MAX_ATTEMPTS) {
    const lockoutKey = `lockout:${userId}`;
    await redisClient.setEx(lockoutKey, LOCKOUT_DURATION, '1');
    await redisClient.del(attemptsKey);
    await redisClient.del(`mfa:${userId}`);
    return true;
  }
  
  return false;
}

async function resetAttempts(userId) {
  const attemptsKey = `attempts:${userId}`;
  await redisClient.del(attemptsKey);
}

app.post('/api/mfa/send', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;
    
    const sanitizedUserId = sanitizeUserId(userId);
    if (!sanitizedUserId) {
      return res.status(400).json({ error: 'Invalid user ID' });
    }
    
    if (!validatePhoneNumber(phoneNumber)) {
      return res.status(400).json({ error: 'Invalid phone number format' });
    }
    
    if (await isUserLockedOut(sanitizedUserId)) {
      return res.status(429).json({ error: 'Account temporarily locked due to too many attempts' });
    }
    
    const code = generateSecureCode();
    const codeHash = crypto.createHash('sha256').update(code).digest('hex');
    
    const mfaKey = `mfa:${sanitizedUserId}`;
    const mfaData = JSON.stringify({
      codeHash,
      phoneNumber,
      timestamp: Date.now()
    });
    
    await redisClient.setEx(mfaKey, CODE_EXPIRATION, mfaData);
    await redisClient.del(`attempts:${sanitizedUserId}`);
    
    await twilioClient.messages.create({
      body: `Your verification code is: ${code}. Valid for 10 minutes.`,
      from: TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
    
    res.json({ 
      success: true, 
      message: 'Verification code sent',
      expiresIn: CODE_EXPIRATION
    });
    
  } catch (error) {
    console.error('Error sending MFA code:', error.message);
    res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/api/mfa/verify', async (req, res) => {
  try {
    const { userId, code } = req.body;
    
    const sanitizedUserId = sanitizeUserId(userId);
    if (!sanitizedUserId) {
      return res.status(400).json({ error: 'Invalid user ID' });
    }
    
    if (typeof code !== 'string' || !/^\d{6}$/.test(code)) {
      return res.status(400).json({ error: 'Invalid code format' });
    }
    
    if (await isUserLockedOut(sanitizedUserId)) {
      return res.status(429).json({ error: 'Account temporarily locked due to too many attempts' });
    }
    
    const mfaKey = `mfa:${sanitizedUserId}`;
    const mfaDataStr = await redisClient.get(mfaKey);
    
    if (!mfaDataStr) {
      await incrementAttempts(sanitizedUserId);
      return res.status(400).json({ error: 'No verification code found or code expired' });
    }
    
    const mfaData = JSON.parse(mfaDataStr);
    const codeHash = crypto.createHash('sha256').update(code).digest('hex');
    
    const isValid = crypto.timingSafeEqual(
      Buffer.from(codeHash, 'hex'),
      Buffer.from(mfaData.codeHash, 'hex')
    );
    
    if (!isValid) {
      const locked = await incrementAttempts(sanitizedUserId);
      if (locked) {
        return res.status(429).json({ error: 'Too many failed attempts. Account locked temporarily.' });
      }
      return res.status(401).json({ error: 'Invalid verification code' });
    }
    
    await redisClient.del(mfaKey);
    await resetAttempts(sanitizedUserId);
    
    const sessionToken = crypto.randomBytes(32).toString('hex');
    const sessionKey = `session:${sessionToken}`;
    await redisClient.setEx(sessionKey, 3600, JSON.stringify({
      userId: sanitizedUserId,
      authenticated: true,
      timestamp: Date.now()
    }));
    
    res.json({ 
      success: true, 
      message: 'Verification successful',
      sessionToken
    });
    
  } catch (error) {
    console.error('Error verifying MFA code:', error.message);
    res.status(500).json({ error: 'Verification failed' });
  }
});

app.post('/api/mfa/validate-session', async (req, res) => {
  try {
    const { sessionToken } = req.body;
    
    if (typeof sessionToken !== 'string' || !/^[a-f0-9]{64}$/.test(sessionToken)) {
      return res.status(400).json({ error: 'Invalid session token format' });
    }
    
    const sessionKey = `session:${sessionToken}`;
    const sessionData = await redisClient.get(sessionKey);
    
    if (!sessionData) {
      return res.status(401).json({ error: 'Invalid or expired session' });
    }
    
    const session = JSON.parse(sessionData);
    
    res.json({ 
      success: true, 
      authenticated: session.authenticated,
      userId: session.userId
    });
    
  } catch (error) {
    console.error('Error validating session:', error.message);
    res.status(500).json({ error: 'Session validation failed' });
  }
});

